import Papa from "papaparse";

export interface CsvRow {
  [key: string]: string;
}

/**
 * Faz o parse do arquivo CSV e retorna um array de objetos.
 */
export function parseCsv(file: File): Promise<CsvRow[]> {
  return new Promise((resolve, reject) => {
    Papa.parse<CsvRow>(file, {
      header: true,
      skipEmptyLines: true,
      complete: (results) => resolve(results.data),
      error: (error) => reject(error),
    });
  });
}

/**
 * Filtra as linhas do CSV que contenham todas as palavras-chave em qualquer coluna.
 * As palavras-chave devem ser separadas por espaço.
 */
export function filterCsvRows(rows: CsvRow[], keyword: string): CsvRow[] {
  if (!keyword) return rows;
  const keywords = keyword
    .split(" ")
    .map(k => k.trim().toLowerCase())
    .filter(Boolean);

  return rows.filter(row =>
    keywords.every(kw =>
      Object.values(row).some(
        value => value && value.toLowerCase().includes(kw)
      )
    )
  );
}

/**
 * Converte um array de objetos de volta para CSV.
 */
export function toCsv(rows: CsvRow[]): string {
  return Papa.unparse(rows);
}
